  ('f443cf4b-3cdb-4eda-ad75-dd0000b7b577', 'KIMCHI-5527', 'Chipsy Caribbean Spiced Chicken 100g - Pringles', 'Chipsy Caribbean Spiced Chicken 100g - Pringles is a flavorful snack with a unique Caribbean spice blend.', 'Chipsy Caribbean Spiced Chicken 100g - Pringles', 'Chipsy Caribbean Spiced Chicken 100g - Pringles is a flavorful snack with a unique Caribbean spice blend.'),
  ('8d103eb5-f028-4edc-8be6-48ff6f09a85a', 'KIMCHI-1416', 'Chipsy Hi Tempura, nori seaweed in tempura 40g - Tao Kae Noi', 'Chipsy Hi Tempura features classic nori seaweed coated in a delicious Japanese tempura batter. A crunchy and unique snack seasoned with garlic, pepper, chili, salt, and sugar.', 'Chipsy Hi Tempura, nori seaweed in tempura 40g - Tao Kae Noi', 'Chipsy Hi Tempura features classic nori seaweed coated in a delicious Japanese tempura batter. A crunchy and unique snack seasoned with garlic, pepper, chili, salt, and sugar.'),
  ('b12ece9b-54ef-496e-ae41-a3baf5a56043', 'KIMCHI-5453', 'Chipsy Hi Tempura, Nori Seaweed in Chili & Lime Tempura 40g - Tao Kae Noi', 'Chipsy Hi Tempura, Nori Seaweed in Chili & Lime Tempura 40g - Tao Kae Noi. A crunchy snack made with seaweed and a spicy lime flavor.', 'Chipsy Hi Tempura, Nori Seaweed in Chili & Lime Tempura 40g - Tao Kae Noi', 'Chipsy Hi Tempura, Nori Seaweed in Chili & Lime Tempura 40g - Tao Kae Noi. A crunchy snack made with seaweed and a spicy lime flavor.')
), matched AS (
  SELECT
    p.salon_id,
    p.id AS template_id,
    s.slug,
    s.product_name,
    s.short_description,
    s.meta_title,
    s.meta_description
  FROM source s
  JOIN channels ch ON ch.slug = 'kenmito' AND ch.is_active = true
  JOIN products p ON p.id = s.template_id::uuid AND p.salon_id = ch.salon_id
  WHERE p.deleted_at IS NULL
), backup_insert AS (
  INSERT INTO kenmito_product_translations_backup_20260627
  SELECT pt.*
  FROM product_translations pt
  JOIN matched m ON m.template_id = pt.template_id AND m.salon_id = pt.salon_id
  WHERE pt.lang_id = 'en'
    AND NOT EXISTS (SELECT 1 FROM kenmito_product_translations_backup_20260627 b WHERE b.id = pt.id)
  RETURNING id
), upserted AS (
  INSERT INTO product_translations (
    id, salon_id, template_id, lang_id, product_name, short_description,
    meta_title, meta_description, created_at, updated_at
  )
  SELECT
    gen_random_uuid(),
    salon_id,
    template_id,
    'en',
    product_name,
    short_description,
    meta_title,
    meta_description,
    NOW(),
    NOW()
  FROM matched
  ON CONFLICT (template_id, lang_id) DO UPDATE SET
    product_name = EXCLUDED.product_name,
    short_description = EXCLUDED.short_description,
    meta_title = EXCLUDED.meta_title,
    meta_description = EXCLUDED.meta_description,
    updated_at = NOW()
  WHERE product_translations.salon_id = EXCLUDED.salon_id
  RETURNING template_id
)
SELECT
  (SELECT COUNT(*) FROM source) AS source_rows,
  (SELECT COUNT(*) FROM matched) AS matched_rows,
  (SELECT COUNT(*) FROM backup_insert) AS backed_up_rows,
  (SELECT COUNT(*) FROM upserted) AS upserted_rows;

-- Verify the printed counts after running. The backup table can be used to restore previous EN rows if needed.
COMMIT;
